const raw = $input.first().json ?? {};
const body = raw.body ?? raw;
const normalize = (value) => String(value ?? '').trim();
const generatedAt = new Date().toISOString();
const allowedActions = new Set(['validate', 'exchange', 'pages', 'full']);
const actionRaw = normalize(body.action || 'full').toLowerCase();
const action = allowedActions.has(actionRaw) ? actionRaw : 'full';
const shortToken = normalize(body.short_token || body.token);
const providedUserToken = normalize(body.long_lived_token || body.user_token || body.long_token);
const pageId = normalize(body.page_id);
const appId = normalize(body.app_id || '795000703662130');
const appSecret = normalize(body.app_secret || '8931002363214470aae2366a92a4f32e');

const buildError = (message, extra = {}) => [{
  json: {
    status: 'error',
    action,
    message,
    generated_at: generatedAt,
    ...extra,
  },
}];

if (!appId || !appSecret) {
  return buildError('Se requiere app_id y app_secret para procesar el token.');
}

if (action === 'validate') {
  return [{
    json: {
      status: 'success',
      action,
      generated_at: generatedAt,
      app_id: appId,
      page_id_requested: pageId || null,
      has_short_token: !!shortToken,
      has_long_lived_token: !!providedUserToken,
      note: 'Validacion local completada. No se hizo llamada a Facebook.',
    },
  }];
}

const skipExchange = action === 'pages' && !!providedUserToken;
if (!skipExchange && !shortToken) {
  return buildError('Se requiere short_token o token en el body.');
}

const request = this.helpers.request;
const requestDefaults = {
  json: true,
  simple: false,
  resolveWithFullResponse: true,
  headers: {
    Accept: 'application/json',
    'User-Agent': 'n8n-token-manager-fb/1.1',
  },
};

let longLivedToken = providedUserToken;
let tokenType = providedUserToken ? 'bearer' : '';
let expiresIn = 0;
let expiresAt = providedUserToken ? 'unknown' : '';
let tokenSource = providedUserToken ? 'request_body' : 'facebook_exchange';

if (!skipExchange) {
  const exchangeResponse = await request({
    ...requestDefaults,
    method: 'GET',
    uri: 'https://graph.facebook.com/v21.0/oauth/access_token',
    qs: {
      grant_type: 'fb_exchange_token',
      client_id: appId,
      client_secret: appSecret,
      fb_exchange_token: shortToken,
    },
  });

  const exchangeBody = exchangeResponse?.body ?? {};
  if (Number(exchangeResponse?.statusCode || 500) >= 400 || !exchangeBody.access_token) {
    return buildError('Facebook no devolvio access_token en el exchange.', {
      facebook_status_code: exchangeResponse?.statusCode ?? null,
      facebook_error: exchangeBody?.error ?? exchangeBody,
    });
  }

  longLivedToken = normalize(exchangeBody.access_token);
  tokenType = normalize(exchangeBody.token_type);
  expiresIn = Number(exchangeBody.expires_in || 0);
  expiresAt = expiresIn > 0
    ? new Date(Date.now() + expiresIn * 1000).toISOString()
    : 'unknown';
}

const result = {
  status: 'success',
  action,
  generated_at: generatedAt,
  app_id: appId,
  page_id_requested: pageId || null,
  token_source: tokenSource,
  long_lived_user_token: longLivedToken,
  token_type: tokenType || null,
  long_lived_expires_in_seconds: expiresIn,
  long_lived_expires_in_days: expiresIn > 0 ? Math.round(expiresIn / 86400) : null,
  long_lived_expires_at: expiresAt || null,
};

if (action === 'exchange') {
  return [{ json: result }];
}

const pagesResponse = await request({
  ...requestDefaults,
  method: 'GET',
  uri: 'https://graph.facebook.com/v21.0/me/accounts',
  qs: {
    access_token: longLivedToken,
    fields: 'name,access_token,id,category',
  },
});

const pagesBody = pagesResponse?.body ?? {};
if (Number(pagesResponse?.statusCode || 500) >= 400 || (pagesBody?.error && !Array.isArray(pagesBody?.data))) {
  return buildError('No se pudieron obtener las paginas del usuario.', {
    facebook_status_code: pagesResponse?.statusCode ?? null,
    facebook_error: pagesBody?.error ?? pagesBody,
  });
}

const pages = Array.isArray(pagesBody.data) ? pagesBody.data : [];
result.pages = pages.map((page) => ({
  page_id: normalize(page.id),
  page_name: normalize(page.name),
  category: normalize(page.category),
  page_access_token: normalize(page.access_token),
  is_permanent: true,
  note: 'Este Page Access Token no expira mientras el User Token siga vigente.',
}));
result.total_pages = pages.length;

if (pageId) {
  const target = pages.find((page) => normalize(page.id) === pageId);
  result.selected_page_found = !!target;
  if (target) {
    result.selected_page = {
      page_id: normalize(target.id),
      page_name: normalize(target.name),
      page_access_token: normalize(target.access_token),
      category: normalize(target.category),
    };
  } else {
    result.selected_page = null;
    result.warning = `Page ID ${pageId} no encontrado en las paginas del usuario.`;
  }
}

return [{ json: result }];
